1	// TemplateSvgIcon.ets
2	//
3	// A model-friendly icon entry template for scaffolded HarmonyOS apps.
4	//
5	// Agent rules:
6	// - Keep the exported struct name as SvgIcon.
7	// - Keep the public API stable: variant, iconSize, color, and strokeWidth.
8	// - Prefer updating fileNameForVariant() and the matching rawfile assets instead of
9	// - hardcoding resource paths in page-level components.
10	// - Keep variant names generic so scaffold components are not tied to one product domain.
11	//
12	// Usage:
13	// - Replace the default rawfile mappings with your real icon assets.
14	// - Keep common variants such as home, explore, orders, rewards, search, profile,
15	// - back, add, remove, and favorite available when practical.
16	// - If the real project uses a different icon system, adapt this wrapper instead of
17	// - changing every caller.
18	//
19	// Notes:
20	// - The default rawfile names are placeholders from the bundled template assets.
21	// - color and strokeWidth are part of the stable template contract even when the
22	// - current rawfile-backed implementation does not apply tinting dynamically.
23	@Component
24	export struct SvgIcon {
25	  @Prop iconSize: number = 24;
26	  @Prop color: string = '#0F3329';
27	  @Prop strokeWidth: number = 2;
28	  @Prop variant: string = 'search';
29	
30	  build() {
31	    Image($rawfile(this.fileNameForVariant()))
32	      .width(this.iconSize)
33	      .height(this.iconSize)
34	      .objectFit(ImageFit.Contain)
35	      .draggable(false)
36	  }
37	
38	  private fileNameForVariant(): string {
39	    const v: string = this.variant;
40	    if (v === 'home') {
41	      return 'icon_首页-1.svg';
42	    } else if (v === 'explore' || v === 'menu') {
43	      return 'icon_菜单-1.svg';
44	    } else if (v === 'store' || v === 'stores') {
45	      return 'icon_门店-1.svg';
46	    } else if (v === 'rewards') {
47	      return 'icon_会员奖励-1.svg';
48	    } else if (v === 'orders' || v === 'history') {
49	      return 'icon_订单历史.svg';
50	    } else if (v === 'profile' || v === 'user') {
51	      return 'icon_进入我的账户.svg';
52	    } else if (v === 'cart') {
53	      return 'icon_查看购物车.svg';
54	    } else if (v === 'search') {
55	      return 'icon_搜索饮品.svg';
56	    } else if (v === 'trending' || v === 'reorder' || v === 'trendingUp') {
57	      return 'icon_一键复购最近订单.svg';
58	    } else if (v === 'add' || v === 'plus') {
59	      return 'icon_增加数量.svg';
60	    } else if (v === 'remove' || v === 'minus') {
61	      return 'icon_减少数量.svg';
62	    } else if (v === 'back') {
63	      return 'icon_返回上一页.svg';
64	    } else if (v === 'favorite' || v === 'heart') {
65	      return 'icon_收藏该饮品.svg';
66	    } else if (v === 'trash') {
67	      return 'icon_从购物车移除该商品.svg';
68	    } else if (v === 'info') {
69	      return 'icon_会员规则.svg';
70	    } else if (v === 'settings') {
71	      return 'icon_打开设置.svg';
72	    } else if (v === 'arrowRight' || v === 'chevronRight') {
73	      return 'icon_进入设置.svg';
74	    } else if (v === 'card') {
75	      return 'icon_支付方式图标.svg';
76	    } else if (v === 'placeholder' || v === 'cup') {
