// ProgressHeader.ets
//
// Shows session progress: remaining / total words and the correct (known) count.
// Binds the semantic assertion targets from ui-tree.json.

import { Theme } from '../common/Theme';

@Component
export struct ProgressHeader {
  @Prop totalCount: number = 0;
  @Prop remainingCount: number = 0;
  @Prop knownCount: number = 0;

  build() {
    Column() {
      Text('单词翻翻乐')
        .fontSize(28)
        .fontWeight(FontWeight.Bold)
        .fontColor(Theme.textPrimary)
      Text('点击卡片翻面，认识点绿，不认识点红')
        .fontSize(14)
        .fontColor(Theme.textSecondary)
        .margin({ top: 6 })

      Row() {
        // Remaining / total
        Column() {
          Text('剩余 / 总数')
            .fontSize(12)
            .fontColor(Theme.textTertiary)
          Row() {
            Text(this.remainingCount.toString())
              .fontSize(28)
              .fontWeight(FontWeight.Bold)
              .fontColor(Theme.brandPrimary)
            Text(' / ')
              .fontSize(20)
              .fontColor(Theme.textTertiary)
            Text(this.totalCount.toString())
              .fontSize(20)
              .fontColor(Theme.textTertiary)
          }
          .alignItems(VerticalAlign.Bottom)
          .margin({ top: 4 })
        }
        .id('review-progress-remaining')
        .alignItems(HorizontalAlign.Start)
        .layoutWeight(1)

        // Hidden assertion anchor carrying total (kept discrete, not double-shown).
        Text(this.totalCount.toString())
          .id('review-progress-total')
          .fontSize(0.1)
          .fontColor(Theme.pageBg)

        // Known / correct count
        Column() {
          Text('已认识')
            .fontSize(12)
            .fontColor(Theme.textTertiary)
          Text(this.knownCount.toString())
            .fontSize(28)
            .fontWeight(FontWeight.Bold)
            .fontColor(Theme.knownGreen)
            .margin({ top: 4 })
        }
        .id('review-progress-known')
        .alignItems(HorizontalAlign.End)
        .layoutWeight(1)
      }
      .width('100%')
      .margin({ top: 18 })
      .padding({ left: 20, right: 20, top: 16, bottom: 16 })
      .borderRadius(Theme.radiusCard)
      .backgroundColor(Theme.cardBg)
    }
    .width('100%')
    .alignItems(HorizontalAlign.Center)
  }
}

