// TemplateTheme.ets
//
// Theme token layer for 单词翻翻乐 (kids vocabulary review app).
// Kid-friendly palette: warm cream page, vibrant purple brand, friendly
// success/warn accents for the 认识 / 不认识 buttons.
//
// Agent rules honored:
// - Kept exported class names: Theme and BrandGradient.
// - Kept layout contract tokens stable: pageHorizontalPadding, bottomTabHeight,
//   contentMaxWidth, touchTarget.
// - Only token values changed to match the real product.

export class Theme {
  // Surfaces
  static readonly pageBg: string = '#FFF6E6';
  static readonly cardBg: string = '#FFFFFF';
  static readonly cardFrontBg: string = '#6C5CE7';
  static readonly cardBackBg: string = '#FFFFFF';

  // Brand
  static readonly brandPrimary: string = '#6C5CE7';
  static readonly brandDark: string = '#3B2BB0';

  // Action accents (kids need big obvious color cues)
  static readonly knownGreen: string = '#27AE60';
  static readonly knownGreenDark: string = '#1E8449';
  static readonly unknownRed: string = '#EB5757';
  static readonly unknownRedDark: string = '#C0392B';
  static readonly accentOrange: string = '#F39C12';
  static readonly gold: string = '#F4B740';

  // Text
  static readonly textPrimary: string = '#2D3436';
  static readonly textSecondary: string = '#636E72';
  static readonly textTertiary: string = '#9DA3A6';
  static readonly textQuaternary: string = '#B2B8BC';
  static readonly textPlaceholder: string = '#C8CDD0';
  static readonly textOnBrand: string = '#FFFFFF';
  static readonly textOnCardFront: string = '#FFFFFF';

