// Flashcard.ets
//
// Single flashcard with a 3D flip animation.
// Front face: English word.
// Back face: Chinese meaning + phonetic.
//
// Animation strategy (reliable in ArkUI):
// - One face is rendered at a time.
// - The face is rotated around the Y axis; animateTo drives `angle` 0<->180.
// - At the midpoint (edge-on, content not visible) we swap which face renders,
//   so the swap is never seen. Back face uses `angle - 180` so it ends readable.
// - The parent owns flip state (controller.isFlipped); this component reacts
//   to the `isFlipped` prop via @Watch and plays the animation.

import { Theme } from '../common/Theme';

@Component
export struct Flashcard {
  @Prop word: string = '';
  @Prop meaning: string = '';
  @Prop phonetic: string = '';
  @Prop isFlipped: boolean = false;
  onTap: () => void = () => {};

  @State private angle: number = 0;
  @State private showFront: boolean = true;
  private animating: boolean = false;

  aboutToAppear(): void {
    this.angle = this.isFlipped ? 180 : 0;
    this.showFront = !this.isFlipped;
  }

  @Watch('isFlipped')
  onFlipChanged(): void {
    this.runFlip();
  }

  private runFlip(): void {
    if (this.animating) {
      return;
    }
    const target: number = this.isFlipped ? 180 : 0;
    this.animating = true;
    animateTo({ duration: 400, curve: Curve.EaseInOut, onFinish: () => {
      this.animating = false;
    } }, () => {
      this.angle = target;
    });
    // Swap face at the midpoint, when the card is edge-on and invisible.
    setTimeout(() => {
      this.showFront = !this.isFlipped;
    }, 200);
  }

  build() {
    Stack() {
      if (this.showFront) {
        Column() {
          Text(this.word)
            .fontSize(56)
            .fontWeight(FontWeight.Bold)
            .fontColor(Theme.textOnCardFront)
            .textAlign(TextAlign.Center)
            .maxLines(2)
            .textOverflow({ overflow: TextOverflow.Ellipsis })
          Text('点我翻面看释义')
            .fontSize(14)
            .fontColor('rgba(255,255,255,0.8)')
            .margin({ top: 24 })
        }
        .width('100%')
        .height('100%')
        .padding({ left: 24, right: 24, top: 24, bottom: 24 })
        .borderRadius(Theme.radiusCard)
        .linearGradient({
          angle: 135,
          direction: GradientDirection.RightTop,
          colors: [['#7A6CF0', 0.0], ['#6C5CE7', 0.5], ['#3B2BB0', 1.0]]
        })
        .justifyContent(FlexAlign.Center)
        .alignItems(HorizontalAlign.Center)
        .rotate({ x: 0, y: 1, z: 0, angle: this.angle, centerX: '50%', centerY: '50%' })
      } else {
        Column() {
          Text(this.meaning)
            .fontSize(44)
            .fontWeight(FontWeight.Bold)
            .fontColor(Theme.textPrimary)
            .textAlign(TextAlign.Center)
            .maxLines(3)
            .textOverflow({ overflow: TextOverflow.Ellipsis })
          Text(this.phonetic)
            .fontSize(22)
            .fontColor(Theme.brandPrimary)
            .margin({ top: 20 })
          Text('点我翻回正面')
            .fontSize(14)
            .fontColor(Theme.textTertiary)
            .margin({ top: 28 })
        }
        .width('100%')
        .height('100%')
