    .rotate({ x: 0, y: 1, z: 0, angle: this.angle - 180, centerX: '50%', centerY: '50%' })
  }
}

// Flashcard.ets
//
// 3D flip flashcard matching page-review-page.html.
//  - 306 x 400 white card, 28px radius, layered shadow.
//  - Front: yellow sparkle (top-right), large English word (center), hint (bottom).
//  - Back: Chinese meaning, thin divider, phonetic, faint "ABC" watermark.
//
// Flip: animateTo drives `angle` 0<->180 around the Y axis with spring easing.
// One face renders at a time; we swap the rendered face at the midpoint (when
// the card is edge-on) so the swap is never visible. The back face uses
// `angle - 180` so it ends readable (not mirrored).
//
// Icons are stroke-painted rawfile SVGs with baked colors; loaded via
// Image($rawfile(...)) with NO fillColor (SVG gate respected).
//
// Semantic targets: review-flashcard, review-card-front-word,
// review-card-back-meaning, review-card-back-phonetic.

import { Theme } from '../common/Theme';

@Component
export struct Flashcard {
  @Prop word: string = '';
  @Prop meaning: string = '';
  @Prop phonetic: string = '';
  @Prop @Watch('onFlipChanged') isFlipped: boolean = false;
  onTap: () => void = () => {};

  @State private angle: number = 0;
  @State private showFront: boolean = true;
  private animating: boolean = false;

  aboutToAppear(): void {
    this.angle = this.isFlipped ? 180 : 0;
    this.showFront = !this.isFlipped;
  }

  onFlipChanged(): void {
    this.runFlip();
  }

  private runFlip(): void {
    if (this.animating) {
      return;
    }
    const target: number = this.isFlipped ? 180 : 0;
    this.animating = true;
    animateTo({ duration: 700, curve: Curve.EaseInOut, onFinish: () => {
      this.animating = false;
    } }, () => {
      this.angle = target;
    });
    // Swap rendered face at the midpoint (card edge-on, content invisible).
    setTimeout(() => {
      this.showFront = !this.isFlipped;
    }, 350);
  }

  build() {
    Stack() {
      if (this.showFront) {
        this.FrontFace()
      } else {
        this.BackFace()
      }
    }
    .id('review-flashcard')
    .width(Theme.cardWidth)
    .height(Theme.cardHeight)
    .onClick(() => {
      if (!this.animating) {
        this.onTap();
      }
    })
  }

  @Builder
  FrontFace() {
    Stack({ alignContent: Alignment.Center }) {
      // Main word, centered
      Text(this.word)
        .id('review-card-front-word')
        .fontSize(54)
        .fontWeight(FontWeight.Bold)
        .fontColor(Theme.ink)
        .textAlign(TextAlign.Center)
        .maxLines(3)
        .textOverflow({ overflow: TextOverflow.Ellipsis })

      // Sparkle decoration, top-right
      Stack({ alignContent: Alignment.TopEnd }) {
        Image($rawfile('icon_Sparkle-decoration-on-flashcard-front.svg'))
          .width(28)
          .height(28)
          .draggable(false)
          .margin({ top: 18, right: 18 })
      }
      .width('100%')
      .height('100%')

      // Hint label, bottom center
      Stack({ alignContent: Alignment.Bottom }) {
        Text('点我查看释义')
          .fontSize(13)
          .fontWeight(FontWeight.Medium)
          .fontColor(Theme.slate)
          .opacity(0.85)
          .margin({ bottom: 24 })
      }
      .width('100%')
      .height('100%')
    }
    .width('100%')
    .height('100%')
    .padding(28)
    .borderRadius(Theme.radiusCard)
    .backgroundColor(Theme.cardBg)
    .shadow({ radius: 56, color: '#1F293721', offsetX: 0, offsetY: 28 })
    .rotate({ x: 0, y: 1, z: 0, angle: this.angle, centerX: '50%', centerY: '50%' })
  }

  @Builder
  BackFace() {
    Stack() {
      Column() {
        Text(this.meaning)
          .id('review-card-back-meaning')
          .fontSize(36)
          .fontWeight(FontWeight.Bold)
          .fontColor(Theme.ink)
          .textAlign(TextAlign.Center)
          .maxLines(4)
          .textOverflow({ overflow: TextOverflow.Ellipsis })

        Divider()
          .color(Theme.cardDivider)
          .strokeWidth(1)
          .width(56)
          .margin({ top: 10, bottom: 10 })

        Text(this.phonetic)
          .id('review-card-back-phonetic')
          .fontSize(20)
          .fontWeight(FontWeight.Regular)
          .fontColor(Theme.slate)
          .textAlign(TextAlign.Center)
      }
      .justifyContent(FlexAlign.Center)
      .alignItems(HorizontalAlign.Center)

      // Faint "ABC" watermark, bottom-right
      Stack({ alignContent: Alignment.BottomEnd }) {
        Text('ABC')
          .fontSize(60)
          .fontWeight(FontWeight.Bold)
          .fontColor('#1F293709')
          .margin({ bottom: 18, right: 20 })
      }
      .width('100%')
      .height('100%')
    }
    .width('100%')
    .height('100%')
    .padding(28)
    .borderRadius(Theme.radiusCard)
    .backgroundColor(Theme.cardBg)
    .shadow({ radius: 56, color: '#1F293721', offsetX: 0, offsetY: 28 })
    .rotate({ x: 0, y: 1, z: 0, angle: this.angle - 180, centerX: '50%', centerY: '50%' })
  }
}

// ReviewPage.ets
//
// The only route-worthy surface: the flashcard review flow.
// Owns the ReviewController (session state machine) and mirrors its state into
// @State fields that drive the reactive UI.
//
// Layout (page-review-page.html):
//  - Sky-blue gradient background with two decorative radial blobs.
//  - White ProgressHeader at the top.
//  - Centered Flashcard stage + ActionBar below it.
//  - CompletionState panel when the queue is exhausted.
// Content is constrained to contentMaxWidth (390vp) and centered; never full-width.

import { Theme, BrandGradient } from '../common/Theme';
import { ReviewController } from '../services/ReviewController';
import { ProgressHeader } from '../components/ProgressHeader';
import { Flashcard } from '../components/Flashcard';
import { ActionBar } from '../components/ActionBar';
import { CompletionState } from '../components/CompletionState';

@Component
export struct ReviewPage {
  private controller: ReviewController = new ReviewController();

  @State private totalCount: number = 0;
  @State private remainingCount: number = 0;
  @State private knownCount: number = 0;
  @State private isComplete: boolean = false;
  @State private currentWord: string = '';
  @State private currentMeaning: string = '';
  @State private currentPhonetic: string = '';
  @State private isFlipped: boolean = false;

  aboutToAppear(): void {
    this.syncFromController();
  }

  private syncFromController(): void {
    const c: ReviewController = this.controller;
    this.totalCount = c.totalCount;
    this.remainingCount = c.remainingCount;
    this.knownCount = c.correctCount;
    this.isComplete = c.isComplete;
    const w = c.currentWord;
    this.currentWord = w ? w.word : '';
    this.currentMeaning = w ? w.meaning : '';
    this.currentPhonetic = w ? w.phonetic : '';
    this.isFlipped = c.isFlipped;
  }

  // flip-card
  private onFlipCard(): void {
    this.controller.flipCard();
    this.isFlipped = this.controller.isFlipped;
  }

  // mark-known
  private onMarkKnown(): void {
    this.controller.markKnown();
    this.syncFromController();
  }

  // mark-unknown
  private onMarkUnknown(): void {
    this.controller.markUnknown();
    this.syncFromController();
  }

  // restart-session
  private onRestart(): void {
    this.controller.restartSession();
    this.syncFromController();
  }

  build() {
    Stack() {
      // Decorative radial blobs (behind content).
      Circle({ width: 340, height: 340 })
        .fill(Theme.blobYellow)
        .position({ x: -90, y: '42%' })

      Circle({ width: 360, height: 360 })
        .fill(Theme.blobPurple)
        .position({ x: 140, y: '12%' })

      // Content column, centered and width-constrained.
      Column() {
        ProgressHeader({
          totalCount: this.totalCount,
          remainingCount: this.remainingCount,
          knownCount: this.knownCount,
        })

        if (this.isComplete) {
          Column() {
            CompletionState({
              knownCount: this.knownCount,
              totalCount: this.totalCount,
              onRestart: () => this.onRestart(),
            })
          }
          .width('100%')
          .layoutWeight(1)
          .justifyContent(FlexAlign.Center)
          .alignItems(HorizontalAlign.Center)
        } else {
          // Card stage + actions
          Column() {
            Flashcard({
              word: this.currentWord,
              meaning: this.currentMeaning,
              phonetic: this.currentPhonetic,
              isFlipped: this.isFlipped,
              onTap: () => this.onFlipCard(),
            })
            ActionBar({
              onKnown: () => this.onMarkKnown(),
              onUnknown: () => this.onMarkUnknown(),
            })
            .margin({ top: 44 })
          }
          .width('100%')
          .layoutWeight(1)
          .justifyContent(FlexAlign.Center)
          .alignItems(HorizontalAlign.Center)
        }
      }
      .width('100%')
      .height('100%')
      .maxWidth(Theme.contentMaxWidth)
    }
    .width('100%')
    .height('100%')
    .linearGradient(BrandGradient.pageTop)
    .alignContent(Alignment.Center)
  }
}

// Index.ets
//
// App shell entry. The product spec defines a single-page review app with no
// tabs/navigation, so this shell hosts the single ReviewPage surface directly.
//
// Note (deviation from scaffold template, recorded in handoff):
// The bundled template shipped a multi-tab shell (BottomTabBar + TabTypes +
// HomePage/ExplorePage/... placeholders). The spec explicitly mandates a
// single-page app with no tabs, so Index is reduced to a single-surface host.
// The scaffold shell files (BottomTabBar, TabTypes, SvgIcon) are retained on
// disk but intentionally unused. Theme.ets is still the shared token layer.

import { ReviewPage } from './ReviewPage';
import { Theme, BrandGradient } from '../common/Theme';

@Entry
@Component
struct Index {
  build() {
    Column() {
      ReviewPage()
    }
    .width('100%')
    .height('100%')
    .linearGradient(BrandGradient.pageTop)
    .alignItems(HorizontalAlign.Center)
  }
}

